#!/usr/bin/env bash
# Generated by OrchestKit Claude Plugin
# Created: 2026-03-26

set -euo pipefail

# Fingerprint Gating for /ork:expect (#1167)
# Usage:
#   bash fingerprint.sh check [target]   — check if fingerprint matches (exit 0=skip, 1=run)
#   bash fingerprint.sh save [target] [flows_run]  — save fingerprint after successful run
#   bash fingerprint.sh clear            — delete stored fingerprint
#
# Fingerprint = SHA-256 of: HEAD commit + staged diff + unstaged diff

COMMAND="${1:-check}"
TARGET="${2:-changes}"
FLOWS_RUN="${3:-0}"

FINGERPRINT_FILE=".expect/last-tested"

# ── Compute current fingerprint ────────────────────────────
compute_fingerprint() {
  local head_hash staged_diff unstaged_diff combined

  head_hash=$(git rev-parse HEAD 2>/dev/null || echo "no-head")
  staged_diff=$(git diff --cached 2>/dev/null || true)
  unstaged_diff=$(git diff 2>/dev/null || true)

  combined="${head_hash}${staged_diff}${unstaged_diff}"

  if command -v shasum &>/dev/null; then
    echo -n "$combined" | shasum -a 256 | cut -d' ' -f1
  elif command -v sha256sum &>/dev/null; then
    echo -n "$combined" | sha256sum | cut -d' ' -f1
  else
    # Fallback: use git hash-object
    echo -n "$combined" | git hash-object --stdin
  fi
}

# ── Check fingerprint ──────────────────────────────────────
check_fingerprint() {
  local current stored_hash

  current=$(compute_fingerprint)

  if [[ ! -f "$FINGERPRINT_FILE" ]]; then
    echo '{"match":false,"reason":"no previous fingerprint","current":"'"$current"'"}'
    return 1
  fi

  stored_hash=$(python3 -c "
import json, sys
try:
    data = json.load(open('$FINGERPRINT_FILE'))
    print(data.get('hash', ''))
except:
    print('')
" 2>/dev/null || echo "")

  if [[ "$current" == "$stored_hash" ]]; then
    echo '{"match":true,"reason":"no changes since last successful run","fingerprint":"'"${current:0:16}"'..."}'
    return 0
  else
    echo '{"match":false,"reason":"code changed since last run","current":"'"${current:0:16}"'...","stored":"'"${stored_hash:0:16}"'..."}'
    return 1
  fi
}

# ── Save fingerprint ───────────────────────────────────────
save_fingerprint() {
  local current timestamp

  current=$(compute_fingerprint)
  timestamp=$(date -u +"%Y-%m-%dT%H:%M:%SZ")

  mkdir -p "$(dirname "$FINGERPRINT_FILE")"

  cat > "$FINGERPRINT_FILE" <<ENDJSON
{
  "hash": "$current",
  "timestamp": "$timestamp",
  "target": "$TARGET",
  "flows_run": $FLOWS_RUN
}
ENDJSON

  echo '{"saved":true,"hash":"'"${current:0:16}"'...","timestamp":"'"$timestamp"'"}'
}

# ── Clear fingerprint ──────────────────────────────────────
clear_fingerprint() {
  if [[ -f "$FINGERPRINT_FILE" ]]; then
    rm -f "$FINGERPRINT_FILE"
    echo '{"cleared":true}'
  else
    echo '{"cleared":false,"reason":"no fingerprint file found"}'
  fi
}

# ── Main ───────────────────────────────────────────────────
case "$COMMAND" in
  check)
    check_fingerprint
    ;;
  save)
    save_fingerprint
    ;;
  clear)
    clear_fingerprint
    ;;
  *)
    echo "Usage: fingerprint.sh [check|save|clear] [target] [flows_run]" >&2
    exit 1
    ;;
esac
